# Permission detection patterns for Claude Code CLI
AGENT_PERMISSION_PATTERNS = [
    re.compile(r"Allow\s+.+\?\s*\([yYnN]/[yYnN]\)", re.I),
    re.compile(r"Do you want to\s+.+\?", re.I),
    re.compile(r"Allow\s+(edit|write|bash|execute|Bash|Edit|Write)", re.I),
    re.compile(r"Yes\s*/\s*No", re.I),
]

# Patterns for auto-approval (file reads only)
AGENT_AUTO_APPROVE_PATTERNS = [
    re.compile(r"Allow\s+read", re.I),
    re.compile(r"Allow\s+Read", re.I),
    re.compile(r"file read", re.I),
]

# ANSI escape code stripper
