class TaskStatus(str, Enum):
    PENDING = "pending"
    PROCESSING = "processing"
    COMPLETED = "completed"
    FAILED = "failed"

class TaskType(str, Enum):
    IMAGE_GENERATION = "image_generation"
    VIDEO_GENERATION = "video_generation"
    AUDIO_ANALYSIS = "audio_analysis"
    GOOGLE_TTS = "google_tts"
    GEMINI_TTS = "gemini_tts"
    LYRIA_MUSIC = "lyria_music"  # Google Lyria-002 music generation
    CHAT = "chat"
    CHECKPOINT = "checkpoint"
    AGENT_CHAT = "agent_chat"  # Claude Code CLI sessions
    BROWSER_USE = "browser_use"  # Legacy — kept for backward compat with old DB rows
    USE_COMPUTER = "use_computer"  # Computer Use agent (Anthropic CU on Linux desktop)
    GEMINI_CU = "gemini_cu"      # Gemini Computer Use (Android/browser via gemini_cu_routes)

@dataclass
class Task:
    task_id: str
    task_type: TaskType
    status: TaskStatus
    created_at: str
    updated_at: str
    prompt: Optional[str] = None
    input_file: Optional[str] = None
    result_url: Optional[str] = None
    result_data: Optional[Dict] = None
    error_message: Optional[str] = None
    progress: int = 0
    operator: Optional[str] = None
    image_data: Optional[Dict] = None  # For image-to-video (stores base64 + mime_type)
    google_video_uri: Optional[str] = None  # Original Google video URI for extensions

class TaskDatabase:
    """SQLite-based task persistence"""
    def __init__(self, db_path: str = "Portal/tasks.db"):
        self.db_path = db_path
        Path(db_path).parent.mkdir(parents=True, exist_ok=True)
        self._init_db()
    
    def _connect(self):
        """Create a SQLite connection with WAL mode and optimized PRAGMAs for concurrent access."""
        conn = sqlite3.connect(self.db_path, timeout=30)
        conn.execute("PRAGMA journal_mode=WAL")
        conn.execute("PRAGMA synchronous=NORMAL")
        conn.execute("PRAGMA cache_size=-64000")
        conn.execute("PRAGMA busy_timeout=5000")
        conn.execute("PRAGMA temp_store=MEMORY")
        return conn

    def _init_db(self):
        conn = self._connect()
        cursor = conn.cursor()
        cursor.execute("""
            CREATE TABLE IF NOT EXISTS tasks (
                task_id TEXT PRIMARY KEY,
                task_type TEXT NOT NULL,
                status TEXT NOT NULL,
                created_at TEXT NOT NULL,
                updated_at TEXT NOT NULL,
                prompt TEXT,
                input_file TEXT,
                result_url TEXT,
                result_data TEXT,
                error_message TEXT,
                progress INTEGER DEFAULT 0,
                operator TEXT,
                image_data TEXT,
                google_video_uri TEXT
            )
        """)

        # Add image_data column if it doesn't exist (for existing databases)
        try:
            cursor.execute("ALTER TABLE tasks ADD COLUMN image_data TEXT")
            conn.commit()
        except sqlite3.OperationalError:
            pass  # Column already exists

        # Add google_video_uri column if it doesn't exist (for existing databases)
        try:
            cursor.execute("ALTER TABLE tasks ADD COLUMN google_video_uri TEXT")
            conn.commit()
        except sqlite3.OperationalError:
            # Column already exists
            pass

        conn.close()
    
    def save_task(self, task: Task):
        conn = self._connect()
        cursor = conn.cursor()
        cursor.execute("""
            INSERT OR REPLACE INTO tasks
            (task_id, task_type, status, created_at, updated_at, prompt, input_file,
             result_url, result_data, error_message, progress, operator, image_data, google_video_uri)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        """, (
            task.task_id, task.task_type, task.status, task.created_at, task.updated_at,
            task.prompt, task.input_file, task.result_url,
            json.dumps(task.result_data) if task.result_data else None,
            task.error_message, task.progress, task.operator,
            json.dumps(task.image_data) if task.image_data else None,
            task.google_video_uri
        ))
        conn.commit()
        conn.close()
    
    def get_task(self, task_id: str) -> Optional[Task]:
        conn = self._connect()
        cursor = conn.cursor()
        cursor.execute("SELECT * FROM tasks WHERE task_id = ?", (task_id,))
        row = cursor.fetchone()
        conn.close()

        if not row:
            return None

        return Task(
            task_id=row[0],
            task_type=TaskType(row[1]),
            status=TaskStatus(row[2]),
            created_at=row[3],
            updated_at=row[4],
            prompt=row[5],
            input_file=row[6],
            result_url=row[7],
            result_data=json.loads(row[8]) if row[8] else None,
            error_message=row[9],
            progress=row[10],
            operator=row[11],
            image_data=json.loads(row[12]) if len(row) > 12 and row[12] else None,
            google_video_uri=row[13] if len(row) > 13 else None
        )
    
    def get_all_tasks(self, operator: Optional[str] = None) -> List[Task]:
        conn = self._connect()
        cursor = conn.cursor()
        if operator:
            cursor.execute("SELECT * FROM tasks WHERE operator = ? ORDER BY created_at DESC", (operator,))
        else:
            cursor.execute("SELECT * FROM tasks ORDER BY created_at DESC")
        rows = cursor.fetchall()
        conn.close()
        
        tasks = []
        for row in rows:
            tasks.append(Task(
                task_id=row[0],
                task_type=TaskType(row[1]),
                status=TaskStatus(row[2]),
                created_at=row[3],
                updated_at=row[4],
                prompt=row[5],
                input_file=row[6],
                result_url=row[7],
                result_data=json.loads(row[8]) if row[8] else None,
                error_message=row[9],
                progress=row[10],
                operator=row[11],
                image_data=json.loads(row[12]) if len(row) > 12 and row[12] else None,
                google_video_uri=row[13] if len(row) > 13 else None
            ))
        return tasks

